https://github.com/libjxl/libjxl/commit/bbe0c3789843 made me pause while -CURRENT fixed the headers. Should build fine now, see http://www.ipv6proxy.net/go.php?u=http://beefy18.nyi.freebsd.org/data/main-amd64-default/p772274a15b8b_s0630a06b2a/logs/mesa-devel-21.3.b.1817.log

A more generic solution can be something like:

--- a/lib/libc/gen/sysconf.c	(git-c1920558b3c4)
+++ b/lib/libc/gen/sysconf.c	(working copy)
@@ -38,6 +38,7 @@ __FBSDID("$FreeBSD$");

 #include "namespace.h"
 #include <sys/param.h>
+#include <sys/cpuset.h>
 #include <sys/time.h>
 #include <sys/sysctl.h>
 #include <sys/resource.h>
@@ -74,6 +75,7 @@ __FBSDID("$FreeBSD$");
 long
 sysconf(int name)
 {
+	cpuset_t cpus;
 	struct rlimit rl;
 	size_t len;
 	int mib[2], sverrno, value;
@@ -583,13 +601,18 @@ sysconf(int name)
 #endif

 	case _SC_NPROCESSORS_CONF:
-	case _SC_NPROCESSORS_ONLN:
 		if (_elf_aux_info(AT_NCPUS, &value, sizeof(value)) == 0)
 			return ((long)value);
 		mib[0] = CTL_HW;
 		mib[1] = HW_NCPU;
 		break;

+	case _SC_NPROCESSORS_ONLN:
+		len = sizeof(cpus);
+		if (cpuset_getaffinity(CPU_LEVEL_WHICH, CPU_WHICH_TID, -1, len, &cpus))
+			return (-1);
+		return CPU_COUNT(&cpus);
+
 #ifdef _SC_PHYS_PAGES
 	case _SC_PHYS_PAGES:
 		len = sizeof(lvalue);
